Port.App<T>() は、[Port] 属性ベースの初期化スタイルを使用する際の必須の最初の呼び出しです。 アプリケーションクラスに [Port] を付けてリポジトリ名とプルパスを宣言し、 他の Port API より前に Port.App<T>() を呼び出してください。 [Port("sample")] public class SampleApp { } // スタートアップ時（例：コンストラクタまたは Program.cs）— 最初に呼び出す必要があります Port.App<SampleApp>(); Port.App<T>() は T の [Port] 属性を読み取り、Port.Repository.New(pullPath, reponame) 経由で リポジトリを作成し、PortDic インスタンスを起動します。 後続のすべての Port.Push、Port.Pull、Port.Repository.Load 呼び出しは、 この初期化の完了に依存しています。 完全なスタートアップ例​ [Port("sample")] public partial class MainWindow : Window { public MainWindow() { InitializeComponent(); try { Port.App<MainWindow>(); #if DEBUG var ioDoc = Port.Document<IOModel>(@"C:\Users\admin\Documents\IO.docx"); ioDoc.Where(v => v.Key.Contains("OnOff")).ToList() .ForEach(v => v.DataType = "Enum.OnOff"); ioDoc.Where(v => v.Key.Contains("Temp")).ToList() .ForEach(v => v.DataType = "f8"); if (ioDoc.Count > 0) { ioDoc.New(@"C:\Users\admin\Documents\sample\.page\io.page"); ioDoc.New(@"C:\Users\admin\Documents\sample\.net\io.cs"); } Port.Push("sample", new CustomEFEM()); Port.Push("sample", ioDoc.NewPage("Device")); Port.Pull("sample", @"D:\PORT\SampleArduinoLib\sample\Repo\pull"); #endif Port.Add<LoadportController, LoadportModel>("LP1"); Port.Add<LoadportController, LoadportModel>("LP2"); Port.OnReady += Port_OnReady; Port.Run(); } catch (Exception ex) { MessageBox.Show( $"{ex.Message}

Inner: {ex.InnerException?.Message}

Stack: {ex.StackTrace}"); } } }
